    // TriggerVolumeData
    void TriggerVolumeData::Read(pugi::xml_node node) {
        std::cout << "[DEBUG] TriggerVolumeData::Read started." << std::endl;
        mShape = utils::xml_get_text_node<TriggerVolumeShape>(node, "shape");
        std::cout << "[DEBUG] shape: " << static_cast<int>(mShape) << std::endl;
        mActivationType = utils::xml_get_text_node<TriggerVolumeActivationType>(node, "triggerActivationType");
        std::cout << "[DEBUG] triggerActivationType: " << static_cast<int>(mActivationType) << std::endl;

        mOffset = read_vec3(node.child("offset"));

        mOnEnter = utils::xml_get_text_node(node, "onEnter");
        std::cout << "[DEBUG] onEnter: " << mOnEnter << std::endl;
        mOnExit = utils::xml_get_text_node(node, "onExit");
        std::cout << "[DEBUG] onExit: " << mOnExit << std::endl;
        mOnStay = utils::xml_get_text_node(node, "onStay");
        std::cout << "[DEBUG] onStay: " << mOnStay << std::endl;
        mLuaCallbackOnEnter = utils::xml_get_text_node(node, "luaCallbackOnEnter");
        std::cout << "[DEBUG] luaCallbackOnEnter: " << mLuaCallbackOnEnter << std::endl;
        mLuaCallbackOnExit = utils::xml_get_text_node(node, "luaCallbackOnExit");
        std::cout << "[DEBUG] luaCallbackOnExit: " << mLuaCallbackOnExit << std::endl;
        mLuaCallbackOnStay = utils::xml_get_text_node(node, "luaCallbackOnStay");
        std::cout << "[DEBUG] luaCallbackOnStay: " << mLuaCallbackOnStay << std::endl;

        mTimeToActivate = utils::xml_get_text_node<float>(node, "timeToActivate");
        std::cout << "[DEBUG] timeToActivate: " << mTimeToActivate << std::endl;

        mUseObjectDimensions = utils::xml_get_text_node<bool>(node, "useGameObjectDimensions");
        std::cout << "[DEBUG] useGameObjectDimensions: " << (mUseObjectDimensions ? "true" : "false") << std::endl;
        mIsKinematic = utils::xml_get_text_node<bool>(node, "isKinematic");
        std::cout << "[DEBUG] isKinematic: " << (mIsKinematic ? "true" : "false") << std::endl;
        mPersistentTimer = utils::xml_get_text_node<bool>(node, "persistentTimer");
        std::cout << "[DEBUG] persistentTimer: " << (mPersistentTimer ? "true" : "false") << std::endl;
        mTriggerOnceOnly = utils::xml_get_text_node<bool>(node, "triggerOnceOnly");
        std::cout << "[DEBUG] triggerOnceOnly: " << (mTriggerOnceOnly ? "true" : "false") << std::endl;
        mTriggerIfNotBeaten = utils::xml_get_text_node<bool>(node, "triggerIfNotBeaten");
        std::cout << "[DEBUG] triggerIfNotBeaten: " << (mTriggerIfNotBeaten ? "true" : "false") << std::endl;

        switch (mShape) {
            case TriggerVolumeShape::Sphere: {
                auto radius = utils::xml_get_text_node<float>(node, "sphereRadius");
                std::cout << "[DEBUG] Sphere shape detected, sphereRadius: " << radius << std::endl;
                mBoundingBox.extent = glm::vec3(radius);
                break;
            }
            case TriggerVolumeShape::Box: {
                float width = utils::xml_get_text_node<float>(node, "boxWidth");
                float height = utils::xml_get_text_node<float>(node, "boxHeight");
                float length = utils::xml_get_text_node<float>(node, "boxLength");
                std::cout << "[DEBUG] Box shape detected, width: " << width << ", height: " << height << ", length: " << length << std::endl;
                mBoundingBox.extent = glm::vec3(width, height, length);
                break;
            }
            case TriggerVolumeShape::Capsule: {
                float radius = utils::xml_get_text_node<float>(node, "capsuleRadius");
                float height = utils::xml_get_text_node<float>(node, "capsuleHeight");
                std::cout << "[DEBUG] Capsule shape detected, capsuleRadius: " << radius << ", capsuleHeight: " << height << std::endl;
                mBoundingBox.extent = glm::vec3(radius, height, radius);
                break;
            }
        }

        if (auto eventsNode = node.child("events")) {
            std::cout << "[DEBUG] Found 'events' node. Reading TriggerVolumeEvents." << std::endl;
            mEvents.Read(eventsNode);
        } else {
            std::cout << "[DEBUG] No 'events' node found in TriggerVolumeData." << std::endl;
        }
        std::cout << "[DEBUG] TriggerVolumeData::Read finished." << std::endl;
    }

    const BoundingBox& TriggerVolumeData::GetBoundingBox() const {
        std::cout << "[DEBUG] Getting TriggerVolumeData BoundingBox." << std::endl;
        return mBoundingBox;
    }

