    // TeleporterData
    void TeleporterData::Read(pugi::xml_node node) {
        std::cout << "[DEBUG] TeleporterData::Read started." << std::endl;
        mDestinationMarkerId = utils::xml_get_text_node<uint32_t>(node, "destinationMarkerId");
        std::cout << "[DEBUG] destinationMarkerId: " << mDestinationMarkerId << std::endl;
        mDeferTriggerCreation = utils::xml_get_text_node<bool>(node, "deferTriggerCreation");
        std::cout << "[DEBUG] deferTriggerCreation: " << (mDeferTriggerCreation ? "true" : "false") << std::endl;

        if (auto triggerVolumeNode = node.child("triggerVolume")) {
            std::cout << "[DEBUG] Found triggerVolume node in TeleporterData." << std::endl;
            mTriggerVolumeData = std::make_unique<TriggerVolumeData>();
            mTriggerVolumeData->Read(triggerVolumeNode);
        } else {
            std::cout << "[DEBUG] No triggerVolume node found in TeleporterData." << std::endl;
        }
        std::cout << "[DEBUG] TeleporterData::Read finished." << std::endl;
    }

