    // Markerset
    bool Markerset::Load(const std::string& path) {
        std::cout << "[DEBUG] Markerset::Load started for path: " << path << std::endl;
        const std::string fullPath = levelDataPath + path;
        if (!std::filesystem::exists(fullPath)) {
            std::cout << "[DEBUG] Markerset: Could not find '" << fullPath << "'." << std::endl;
            return false;
        }

        pugi::xml_document document;
        if (auto parse_result = document.load_file(fullPath.c_str())) {
            std::cout << "[DEBUG] Markerset XML file loaded: " << fullPath << std::endl;
            auto node = document.child("markerset");
            if (node) {
                Read(node);
                std::cout << "[DEBUG] Markerset::Load finished successfully." << std::endl;
                return true;
            }
        } else {
            std::cout << "[DEBUG] Markerset: Could not load '" << path << "'." << std::endl;
        }
        std::cout << "[DEBUG] Markerset::Load failed." << std::endl;
        return false;
    }

    void Markerset::Read(pugi::xml_node node) {
        std::cout << "[DEBUG] Markerset::Read started." << std::endl;
        for (const auto& child : node.child("markers")) {
            if (!utils::string_iequals(child.name(), "entry")) {
                continue;
            }
            std::cout << "[DEBUG] Reading a Marker entry in Markerset." << std::endl;
            auto marker = std::make_shared<Marker>();
            marker->Read(child);
            mMarkersByNoun[marker->mNoun].push_back(marker);
            mMarkers.push_back(std::move(marker));
        }
        std::cout << "[DEBUG] Markerset::Read finished." << std::endl;
    }

    const std::vector<MarkerPtr>& Markerset::GetMarkers() const {
        std::cout << "[DEBUG] Getting all Markerset Markers." << std::endl;
        return mMarkers;
    }

    std::vector<MarkerPtr> Markerset::GetMarkersByType(uint32_t noun) const {
        std::cout << "[DEBUG] Getting Markerset Markers by type (noun): " << noun << std::endl;
        if (auto it = mMarkersByNoun.find(noun); it != mMarkersByNoun.end()) {
            return it->second;
        }
        std::cout << "[DEBUG] No Markerset Markers found for noun: " << noun << std::endl;
        return {};
    }

