    bool Level::Load(const std::string& difficultyName, const std::string& levelName) {
        std::cout << "[DEBUG] Level::Load started for difficulty: " << difficultyName << ", level: " << levelName << std::endl;
        const std::string fullPath = levelDataPath + difficultyName + "/" + levelName + ".level.xml";
        if (!std::filesystem::exists(fullPath)) {
            std::cout << "[DEBUG] Level: Could not find '" << fullPath << "'." << std::endl;
            return false;
        }

        pugi::xml_document document;
        if (auto parse_result = document.load_file(fullPath.c_str())) {
            std::cout << "[DEBUG] Level XML file loaded: " << fullPath << std::endl;
            auto node = document.child("level");
            if (!node) {
                std::cout << "[DEBUG] No 'level' node found in XML." << std::endl;
                return false;
            }

            for (const auto& child : node.child("markersets")) {
                if (!utils::string_iequals(child.name(), "entry")) {
                    continue;
                }

                const auto markersetAsset = utils::xml_get_text_node(child, "markersetAsset");
                std::cout << "[DEBUG] Found markersetAsset: " << markersetAsset << std::endl;
                if (markersetAsset.empty()) {
                    std::cout << "[DEBUG] markersetAsset is empty, skipping entry." << std::endl;
                    continue;
                }

                const auto& [it, added] = mMarkersets.try_emplace(utils::hash_id(markersetAsset));
                if (added) {
                    it->second.mName = markersetAsset;
                    std::string markersetPath = difficultyName + "/" + markersetAsset + ".xml";
                    std::cout << "[DEBUG] Loading Markerset from: " << markersetPath << std::endl;
                    it->second.Load(markersetPath);
                }
            }

            mConfig.Read(node.child("levelConfig"));
            mFirstTimeConfig.Read(node.child("firstTimeConfig"));

            const auto planetConfigName = utils::xml_get_text_node(node, "planetConfig");
            if (!planetConfigName.empty()) {
                std::cout << "[DEBUG] Found planetConfig: " << planetConfigName << ". (Not processed)" << std::endl;
                // mPlanetConfig.Read(open_the_file);
            }

            std::cout << "[DEBUG] Level::Load finished successfully." << std::endl;
            return true;
        } else {
            std::cout << "[DEBUG] Level: Could not load '" << fullPath << "'." << std::endl;
        }
        std::cout << "[DEBUG] Level::Load failed." << std::endl;
        return false;
    }

    bool Level::GetMarkerset(const std::string& name, Markerset& markerset) const {
        std::cout << "[DEBUG] Level::GetMarkerset called for name: " << name << std::endl;
        if (auto it = mMarkersets.find(utils::hash_id(name)); it != mMarkersets.end()) {
            markerset = it->second;
            std::cout << "[DEBUG] Markerset found for name: " << name << std::endl;
            return true;
        }
        std::cout << "[DEBUG] No markerset found for name: " << name << std::endl;
        return false;
    }

